variables.notification_title:
{% if total_alarms > 1 %}
  MULTIPLE ALARMS
{% elif co_alarms | length > 0 %}
  CARBON MONOXIDE DETECTED
{% else %}
  SMOKE DETECTED
{% endif %}

variables.notification_message:
{% if co_alarms | length > 0 and smoke_alarms | length > 0 %}
  CO: {{ co_alarms | join(', ') }} | SMOKE: {{ smoke_alarms | join(', ') }}
{% elif co_alarms | length > 0 %}
  {{ co_alarms | join(', ') }}
{% else %}
  {{ smoke_alarms | join(', ') }}
{% endif %}

variables.voice_message:
{% if total_alarms > 1 %}
  Multiple alarms! 
{% elif co_alarms | length > 0 %}
  Emergency! 
{% else %}
  Alert! 
{% endif %}
{% if co_alarms | length > 0 %}
  Carbon monoxide detected in {{ co_alarms | join(', ') }}. 
{% endif %}
{% if smoke_alarms | length > 0 %}
  Smoke detected in {{ smoke_alarms | join(', ') }}. 
{% endif %}
{% if smoke_alarms | length > 0 %}
  HVAC has been shut down. 
{% endif %}
{% if co_alarms | length > 0 %}
  Evacuate the house immediately and call 911.
{% else %}
  Check for fire immediately. Evacuate if necessary.
{% endif %}

